import java.util.*;
import java.util.stream.*;

public class DependencyScopeResolver {

    public enum Scope { COMPILE, TEST, RUNTIME, PROVIDED }

    public record Dep(String name, Scope scope) {}

    public List<String> compileClasspath(List<Dep> deps) {
        // Return names of deps on compile classpath: COMPILE and PROVIDED
        return new ArrayList<>();
    }

    public List<String> testClasspath(List<Dep> deps) {
        // Return names of deps on test classpath: COMPILE, TEST, RUNTIME, PROVIDED
        return new ArrayList<>();
    }

    public List<String> runtimeClasspath(List<Dep> deps) {
        // Return names of deps on runtime classpath: COMPILE and RUNTIME
        return new ArrayList<>();
    }

    public static void main(String[] args) {
        DependencyScopeResolver resolver = new DependencyScopeResolver();
        List<Dep> deps = List.of(
            new Dep("spring-core", Scope.COMPILE),
            new Dep("junit", Scope.TEST),
            new Dep("logback", Scope.RUNTIME),
            new Dep("servlet-api", Scope.PROVIDED)
        );
        System.out.println("Compile: " + resolver.compileClasspath(deps));
        System.out.println("Test: " + resolver.testClasspath(deps));
        System.out.println("Runtime: " + resolver.runtimeClasspath(deps));
    }
}
